export enum ModelType {
  FLASH = 'gemini-2.5-flash-image',
  IMAGEN = 'imagen-4.0-generate-001',
  TTS = 'gemini-2.5-flash-preview-tts',
  NATIVE_AUDIO = 'gemini-2.5-flash-native-audio-preview-09-2025'
}

export enum GenerationMode {
  IMAGE = 'image',
  AUDIO = 'audio',
  THUMBNAIL = 'thumbnail'
}

export type VoiceName = 'Puck' | 'Charon' | 'Kore' | 'Fenrir' | 'Zephyr';

export enum AspectRatio {
  SQUARE = '1:1',
  LANDSCAPE_4_3 = '4:3',
  LANDSCAPE_16_9 = '16:9',
  PORTRAIT_3_4 = '3:4',
  PORTRAIT_9_16 = '9:16'
}

export enum ImageResolution {
  RES_1K = '1K',
  RES_2K = '2K',
  RES_4K = '4K'
}

export interface GeneratedContent {
  id: string;
  type: 'image' | 'audio';
  url: string;
  prompt: string;
  model: string;
  timestamp: number;
  aspectRatio?: string; // Only for images
  voice?: VoiceName;    // Only for audio
}

export interface GenerationConfig {
  mode: GenerationMode;
  prompt: string;
  model: ModelType;
  aspectRatio: AspectRatio;
  resolution?: ImageResolution;
  count?: number;
  stylePrompts: string[];
  voice: VoiceName;
  thumbnailTitle?: string;
  referenceImage?: string | null; // Base64 string of uploaded reference
  audioInput?: string | null; // Base64 string of recorded audio for S2S
}

// Interface for the AI Studio client on window
export interface AIStudio {
  hasSelectedApiKey: () => Promise<boolean>;
  openSelectKey: () => Promise<void>;
}
```

