            <>
              Generate {config.mode === GenerationMode.AUDIO ? 'Speech' : config.mode === GenerationMode.THUMBNAIL ? 'Thumbnail' : 'Image'}
              <Zap className="w-4 h-4 fill-current" />
            </>
          )}
        </button>
      </div>
    </div>
  );
};

